// Apply defaults, Bridge Custom Advantages & Append Universal Advantages
powers.forEach(p => {
    p.image = "spritesheet.png";
    p.spriteX = p.spriteX || 0;
    p.spriteY = p.spriteY || 0;
    p.width = p.width || 0;
    p.height = p.height || 0;
    p.renderScale = p.renderScale || 1.0;
    if (p.tier !== "EB") p.tier = Number(p.tier); 
    
    // Core built-in advantages
    p.adv = [{ name: "Rank 2", cost: 2 }, { name: "Rank 3", cost: 2 }];

    // Inject Custom Hardcoded advantages
    if (typeof customAdvantages !== 'undefined' && customAdvantages[p.id]) {
        customAdvantages[p.id].forEach(a => p.adv.push({ name: a[0], cost: a[1] }));
    }

    // Inject the New Parsed Advantages from the Text Files
    if (rawAdvOverrides[p.name]) {
        rawAdvOverrides[p.name].forEach(a => {
            if (!p.adv.some(existingAdv => existingAdv.name.toLowerCase() === a[0].toLowerCase())) {
                p.adv.push({ name: a[0], cost: a[1] });
            }
        });
    }

    // Icon Bridging Logic
    if (typeof HCData !== 'undefined' && typeof spriteData !== 'undefined') {
        let match = HCData.power.find(hp => hp && hp.name && hp.name.toLowerCase() === p.name.toLowerCase());
        if (match) {
            p.desc = (match.toolTip || p.desc).replace(/"/g, '&quot;').replace(/\n/g, '<br>');
            
            if (match.advantageList) {
                match.advantageList.forEach(a => {
                    if (a && a.name && !p.adv.some(existingAdv => existingAdv.name.toLowerCase() === a.name.toLowerCase())) {
                        let safeName = a.name.replace(/"/g, '\\"');
                        p.adv.push({ name: safeName, cost: a.points || 2 });
                    }
                });
            }
            
            if (p.width === 0) {
                let frameworkList = (HCData.framework && Array.isArray(HCData.framework[0])) ? HCData.framework[0] : (HCData.framework || []);
                let frameworkObj = frameworkList.find(f => f.id === match.framework);
                
                let fNameSprite = frameworkObj && frameworkObj.name ? frameworkObj.name.replace(/[^a-zA-Z0-9]/g, "") : "";
                let pNameSprite = match.name.replace(/[^a-zA-Z0-9]/g, "");
                let pSetSprite = p.set.replace(/_/g, ""); 
                
                let possibleKeys = [];
                if (match.icon) possibleKeys.push(match.icon.toLowerCase());
                if (match.iconOverride) possibleKeys.push(match.iconOverride.toLowerCase());
                if (fNameSprite) possibleKeys.push((fNameSprite + "_" + pNameSprite).toLowerCase());
                possibleKeys.push((pSetSprite + "_" + pNameSprite).toLowerCase());
                
                let allFrameworks = ["MartialArts", "Technology", "Brick", "EnergyProjector", "Mentalist", "Mystic", "Shared", "DualBlades", "FightingClaws", "SingleBlade", "Unarmed", "Munitions", "Gadgeteering", "PowerArmor", "LaserSword", "Archery", "Force", "Fire", "Ice", "Wind", "Electricity", "Telepathy", "Telekinesis", "HeavyWeapon", "Earth", "Might", "Celestial", "Darkness", "ArcaneSorcery", "BestialSupernatural", "InfernalSupernatural"];
                
                allFrameworks.forEach(fw => {
                    possibleKeys.push((fw + "_" + pNameSprite).toLowerCase());
                });
                
                let actualKey = Object.keys(spriteData.frames).find(k => possibleKeys.includes(k.toLowerCase()));
                
                if (actualKey && spriteData.frames[actualKey]) {
                    let frame = spriteData.frames[actualKey].frame;
                    p.spriteX = frame.x; p.spriteY = frame.y; p.width = frame.w; p.height = frame.h;
                } else if (spriteData.frames["Any_Generic"]) {
                    let frame = spriteData.frames["Any_Generic"].frame;
                    p.spriteX = frame.x; p.spriteY = frame.y; p.width = frame.w; p.height = frame.h;
                }
            }
        }
    }
});
// --- SHARED POWERS ROUTING MAPPING ---
