// ----------------------------------------

// Bridge Specialization Trees
if (typeof HCData !== 'undefined' && HCData.specializationTree && typeof spriteData !== 'undefined') {
    HCData.specializationTree.forEach(tree => {
        if (!tree || !tree.name) return;

        let newTree = { 
            id: tree.id !== undefined ? tree.id : tree.name, 
            name: tree.name, 
            desc: tree.tip || tree.toolTip || "", 
            perks: [], 
            mastery: null 
        };

        if (tree.specializationList && Array.isArray(tree.specializationList)) {
            tree.specializationList.forEach((perk, index) => {
                if (!perk || (!perk.name && !perk.desc)) return;
                
                let perkName = perk.name || perk.desc; 
                let fNameSprite = tree.name.replace(/[^a-zA-Z0-9]/g, "");
                let pNameSprite = perkName.replace(/[^a-zA-Z0-9]/g, "");
                
                let possibleKeys = [];
                if (perk.icon) possibleKeys.push(perk.icon.toLowerCase());
                if (perk.iconOverride) possibleKeys.push(perk.iconOverride.toLowerCase());
                possibleKeys.push((fNameSprite + "_" + pNameSprite).toLowerCase());
                possibleKeys.push(("Spec_" + fNameSprite + "_" + pNameSprite).toLowerCase());
                possibleKeys.push(("Spec_" + pNameSprite).toLowerCase());
                possibleKeys.push(("Stat_" + fNameSprite).toLowerCase());
                possibleKeys.push(("Stat_" + pNameSprite).toLowerCase());

                let actualKey = Object.keys(spriteData.frames).find(k => possibleKeys.includes(k.toLowerCase()));
                
                let frame = { x: 0, y: 0, w: 24, h: 32 }; 
                if (actualKey && spriteData.frames[actualKey]) {
                    frame = spriteData.frames[actualKey].frame;
                } else if (spriteData.frames["Any_Generic"]) {
                    frame = spriteData.frames["Any_Generic"].frame;
                }
                
                let isMastery = perkName.toLowerCase().includes("mastery");
                let pId = perk.id !== undefined ? perk.id : index;
                
                let perkData = { 
                    id: "spec_" + newTree.id + "_" + pId, 
                    name: perkName, 
                    desc: (perk.tip || perk.toolTip || "").replace(/"/g, '&quot;').replace(/\n/g, '<br>'), 
                    maxPoints: perk.maxPoints !== undefined ? perk.maxPoints : (perk.maxRank !== undefined ? perk.maxRank : (isMastery ? 1 : 3)), 
                    tier: perk.tier || 1, 
                    spriteX: frame.x, spriteY: frame.y, width: frame.w, height: frame.h, renderScale: 1.0, image: "spritesheet.png" 
                };
                
                if (isMastery) newTree.mastery = perkData; 
                else newTree.perks.push(perkData);
            });
        }
        specializations.push(newTree);
    });
} else {
    console.error("CRITICAL ERROR: Could not locate HCData.specializationTree!");
}